# Shapes module that imports and uses math utilities

from math_utils import PI, square, MathHelper

class Shape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def describe(self) -> str:
        ...

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle"

class Circle(Shape):
    radius: float

    def __init__(self, r: float):
        self.radius = r

    @override
    def area(self) -> float:
        return PI * self.radius * self.radius

    @override
    def describe(self) -> str:
        return "Circle"

def calculate_with_helper(base: int, helper: MathHelper) -> int:
    squared: int = square(base)
    return helper.scale(squared)
